mapper.update:
UPDATE sms_seckill_order_log
SET
    order_id = #{orderId},
    status = 1,
    update_time = #{updatedAt}
WHERE
    member_id = #{memberId}
    AND relation_id = #{relationId}

UPDATE sms_flash_promotion_product_relation
SET flash_promotion_count = flash_promotion_count - #{quantity}
WHERE
    id = #{relationId}
    AND flash_promotion_count >= #{quantity}

mapper.select:
SELECT flash_promotion_count
FROM sms_flash_promotion_product_relation
WHERE id = #{relationId}
